parameters.jsCode:
const output = $input.first().json.output || $input.first().json.text || '';
let result = {};
try {
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) result = JSON.parse(jsonMatch[0]);
} catch(e) {}
if (!result.formId) {
  const uuidMatch = output.match(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/i);
  if (uuidMatch) result.formId = uuidMatch[0];
}
// Fix formUrl: extract slug from any malformed URL and rebuild correctly
if (result.formUrl) {
  if (!result.formUrl.startsWith('http')) {
    result.formUrl = 'https://formfex.com/forms/response/' + result.formUrl;
  } else if (!result.formUrl.includes('/forms/response/')) {
    const slug = result.formUrl.split('/').pop();
    result.formUrl = 'https://formfex.com/forms/response/' + slug;
  }
}
if (!result.formUrl) {
  const urlMatch = output.match(/https:\/\/formfex\.com\/forms\/response\/[\w-]+/);
  if (urlMatch) result.formUrl = urlMatch[0];
}
if (!result.formUrl && result.shareUrl) {
  result.formUrl = 'https://formfex.com/forms/response/' + result.shareUrl;
}
if (!result.formUrl && result.formId) {
  result.formUrl = 'https://formfex.com/forms/response/' + result.formId;
}
return [{ json: result }];

