const output = $input.first().json.output || $input.first().json.text || '';
let result = { quality: 'LOW', applicantName: 'Unknown', summary: '', strengths: '', concerns: '' };
try {
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    result.quality = (parsed.quality || 'LOW').toUpperCase();
    result.applicantName = parsed.applicantName || 'Unknown';
    result.summary = parsed.summary || '';
    result.strengths = parsed.strengths || '';
    result.concerns = parsed.concerns || '';
  }
} catch(e) {
  result.summary = output.substring(0, 500);
}
return [{ json: result }];

